SELECT [Sales Invoice Header].[Sell-to Customer No_], [Sales Invoice Header].[Sell-to Customer Name], Dimensioni_NE.CCR, Dimensioni_NE.MARCHIO, Dimensioni_NE.STAGIONE, Dimensioni_NE.LINEA, [Sales Invoice Header].No_, [Sales Invoice Header].[posting date], [Sales Invoice Header].[Salesperson Code], [Sales Invoice Header].[Area Manager Code], [Sales Invoice Header].[Subject 1], [Sales Invoice Header].[Subject 2], Val([Sales Invoice Line.Salesperson Commission _]) AS SalespersonCommission, Val([Sales Invoice Line.Area Manager Commission _]) AS AreaManagerCommission, Val([Sales Invoice Line.Subject 1 Commission _]) AS Subject1Commission, Val([Sales Invoice Line.Subject 2 Commission _]) AS Subject2Commission, [Sales Invoice Line].No_, [Sales Invoice Line].[Description 2], [Sales Invoice Line].[Constant Variable Code] AS Color, IIf(Val([quantity])>0,Val([Sales Invoice Line.Unit Price])/Val([no_ of pairs]),0) AS PrezzoUnitario, Val([Sales invoice line.Line amount])+Val([Sales Invoice Line.Line Discount Amount]) AS importoLordoRIga, Val([sales invoice line.amount]) AS importoNettoRIga, [Sales Invoice Header].[Invoice Disc_ Code], Val([Sales invoice Line.Inv_ Discount Amount]) AS ImportoScontoFattura, Val([Sales Invoice Line.Line Discount Amount]) AS ImportoScontoRIga, [Sales Invoice Line].[VAT Identifier], [Sales Invoice Line].type, [Sales Invoice Line].[Dimension Set ID], [Sales Invoice Line].[Shipment No_], [Sales Invoice Line].[Shipment Line No_], Item.[Tariff No_], Item.[Country_Region of Origin Code]
FROM (([Sales Invoice Line] INNER JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_) INNER JOIN Item ON [Sales Invoice Line].No_ = Item.No_) LEFT JOIN Dimensioni_NE ON [Sales Invoice Line].[Dimension Set ID] = Dimensioni_NE.[Dimension Set ID]
WHERE ((([Sales Invoice Header].[Sell-to Customer No_])=[forms]![principale]![filtroclienteean]) AND (([Sales Invoice Line].No_)=[forms]![principale]![item_control]) AND (([Sales Invoice Line].[Constant Variable Code])=[forms]![principale]![color_control]) AND (([Sales Invoice Line].type)=19 Or ([Sales Invoice Line].type)=20));

